using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
            // Preserve the old name so existing documents (and direct SQL queries
            // referencing c.Discriminator) continue to work.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id generation from "Product|123" to just "123".
            // Preserve the old compound format so existing 500K documents remain
            // accessible via FindAsync / point-reads.
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } = default!; }

